{
  "name": "ReasonMath AI",
  "description": "An AI-powered math testing platform that evaluates not just the answer, but the reasoning behind it."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Option {
  id: string;
  text: string;
}

export interface Question {
  id: string;
  text: string;
  options: Option[];
  // We keep correct answer/reason hidden from the user state until results, 
  // but stored in the app state for the AI to verify (or AI can verify blindly if we send context back).
  // Ideally, the AI generates the quiz and sends us the "truth" which we store but don't show.
  correctOptionId?: string; 
  correctReasoning?: string;
}

export interface UserResponse {
  questionId: string;
  selectedOptionId: string;
  reasoning: string;
}

export interface QuestionEvaluation {
  questionId: string;
  answerScore: number; // Max 5
  reasonScore: number; // Max 5
  totalScore: number;
  isAnswerCorrect: boolean;
  reasonFeedback: string;
  correctReasoning: string; // The AI's better explanation
  correctOptionId: string;
}

export interface QuizResult {
  evaluations: QuestionEvaluation[];
  totalScore: number;
  maxScore: number;
  summary: string;
}

export enum AppState {
  WELCOME = 'WELCOME',
  GENERATING = 'GENERATING',
  QUIZ = 'QUIZ',
  SUBMITTING = 'SUBMITTING',
  RESULTS = 'RESULTS',
  ERROR = 'ERROR'
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { Question, UserResponse, QuizResult, QuestionEvaluation } from "../types";

// NOTE: In a real app, API_KEY should be handled securely. 
// For this frontend-only demo, we expect it in process.env.
const apiKey = process.env.API_KEY || '';

const ai = new GoogleGenAI({ apiKey });

const QUIZ_SCHEMA: Schema = {
  type: Type.ARRAY,
  items: {
    type: Type.OBJECT,
    properties: {
      id: { type: Type.STRING },
      text: { type: Type.STRING },
      options: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            id: { type: Type.STRING },
            text: { type: Type.STRING }
          },
          required: ["id", "text"]
        }
      },
      correctOptionId: { type: Type.STRING },
      correctReasoning: { type: Type.STRING }
    },
    required: ["id", "text", "options", "correctOptionId", "correctReasoning"]
  }
};

const EVALUATION_SCHEMA: Schema = {
  type: Type.OBJECT,
  properties: {
    evaluations: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          questionId: { type: Type.STRING },
          answerScore: { type: Type.NUMBER, description: "Score for correct option (0 or 5)" },
          reasonScore: { type: Type.NUMBER, description: "Score for reasoning (0 to 5)" },
          totalScore: { type: Type.NUMBER },
          isAnswerCorrect: { type: Type.BOOLEAN },
          reasonFeedback: { type: Type.STRING },
          correctReasoning: { type: Type.STRING },
          correctOptionId: { type: Type.STRING }
        },
        required: ["questionId", "answerScore", "reasonScore", "totalScore", "isAnswerCorrect", "reasonFeedback", "correctReasoning", "correctOptionId"]
      }
    },
    totalScore: { type: Type.NUMBER },
    maxScore: { type: Type.NUMBER },
    summary: { type: Type.STRING }
  },
  required: ["evaluations", "totalScore", "maxScore", "summary"]
};

export const generateQuiz = async (topic: string, difficulty: string, count: number = 5): Promise<Question[]> => {
  const model = "gemini-2.5-flash";

  const prompt = `
    Generate ${count} multiple-choice math questions on the topic of "${topic}" with "${difficulty}" difficulty.
    For each question, provide 4 options. 
    One option must be correct.
    Provide the ID of the correct option and a detailed explanation of the logic/math proof as 'correctReasoning'.
    Ensure the questions require some calculation or logical deduction.
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: QUIZ_SCHEMA,
        systemInstruction: "You are a helpful and rigorous mathematics teacher. Output strict JSON."
      }
    });

    const text = response.text;
    if (!text) throw new Error("No content generated");

    return JSON.parse(text) as Question[];
  } catch (error) {
    console.error("Quiz Generation Error:", error);
    throw error;
  }
};

export const evaluateQuiz = async (questions: Question[], userResponses: UserResponse[]): Promise<QuizResult> => {
  const model = "gemini-2.5-flash";

  // Prepare a prompt that includes both the original questions (with truth) and user answers
  const dataForAI = questions.map(q => {
    const userResp = userResponses.find(ur => ur.questionId === q.id);
    return {
      questionId: q.id,
      questionText: q.text,
      options: q.options,
      correctOptionId: q.correctOptionId,
      goldenReasoning: q.correctReasoning,
      userSelectedOptionId: userResp?.selectedOptionId || "NO_ANSWER",
      userReasoning: userResp?.reasoning || "NO_REASONING"
    };
  });

  const prompt = `
    Evaluate the following student responses to math questions.

    Scoring Rules:
    1. Answer Score (max 5): Give 5 points if 'userSelectedOptionId' matches 'correctOptionId'. Else 0.
    2. Reason Score (max 5): Evaluate 'userReasoning'. 
       - If the logic implies the correct mathematical steps, give high marks (4-5).
       - If the logic is flawed but arrives at the right answer by luck, give low marks (1-2).
       - If the logic is non-existent or irrelevant, give 0.
       - Even if the answer option is wrong, if the reasoning has some merit, partial credit can be given (1-3).

    Provide helpful feedback in 'reasonFeedback' explaining exactly why the reasoning was good or bad.

    Data to evaluate:
    ${JSON.stringify(dataForAI, null, 2)}
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: EVALUATION_SCHEMA,
        systemInstruction: "You are a fair but strict math grader. You value the process as much as the result."
      }
    });

    const text = response.text;
    if (!text) throw new Error("No evaluation generated");

    return JSON.parse(text) as QuizResult;
  } catch (error) {
    console.error("Evaluation Error:", error);
    throw error;
  }
};

import React from 'react';

