import React from 'react';
import { Question, UserResponse } from '../types';
import { Icons } from '../constants';

interface QuizCardProps {
  question: Question;
  response?: UserResponse;
  onOptionSelect: (optionId: string) => void;
  onReasonChange: (reason: string) => void;
  questionIndex: number;
  totalQuestions: number;
  onNext: () => void;
  onPrev: () => void;
  onSave: () => void; // Visual cue primarily
}

const QuizCard: React.FC<QuizCardProps> = ({
  question,
  response,
  onOptionSelect,
  onReasonChange,
  questionIndex,
  totalQuestions,
  onNext,
  onPrev,
  onSave
}) => {
  const currentReason = response?.reasoning || "";
  const currentSelection = response?.selectedOptionId || "";

  return (
    <div className="max-w-3xl mx-auto w-full bg-white shadow-xl rounded-2xl overflow-hidden border border-slate-100">
      {/* Header */}
      <div className="bg-slate-900 text-white px-6 py-4 flex justify-between items-center">
        <span className="font-semibold tracking-wide text-sm uppercase text-slate-300">Question {questionIndex + 1} of {totalQuestions}</span>
        <div className="flex items-center space-x-2">
            <span className="text-xs font-mono bg-slate-800 px-2 py-1 rounded text-slate-400">Math Quiz</span>
        </div>
      </div>

      <div className="p-6 md:p-8">
        {/* Question Text */}
        <div className="mb-8">
          <h2 className="text-xl md:text-2xl font-bold text-slate-800 leading-relaxed">
            {question.text}
          </h2>
        </div>

        {/* Options Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-8">
          {question.options.map((option) => (
            <button
              key={option.id}
              onClick={() => onOptionSelect(option.id)}
              className={`
                relative p-4 rounded-xl border-2 text-left transition-all duration-200 flex items-center group
                ${currentSelection === option.id 
                  ? 'border-indigo-600 bg-indigo-50 shadow-md' 
                  : 'border-slate-200 hover:border-indigo-300 hover:bg-slate-50'
                }
              `}
            >
              <div className={`
                w-6 h-6 rounded-full border-2 mr-3 flex items-center justify-center flex-shrink-0 transition-colors
                ${currentSelection === option.id 
                  ? 'border-indigo-600 bg-indigo-600' 
                  : 'border-slate-300 group-hover:border-indigo-400'
                }
              `}>
                {currentSelection === option.id && <div className="w-2 h-2 bg-white rounded-full" />}
              </div>
              <span className={`text-base font-medium ${currentSelection === option.id ? 'text-indigo-900' : 'text-slate-700'}`}>
                {option.text}
              </span>
            </button>
          ))}
        </div>

        {/* Reasoning Input */}
        <div className="mb-8">
          <label className="block text-sm font-semibold text-slate-700 mb-2 flex items-center">
            <Icons.BrainCircuit className="w-4 h-4 mr-2 text-indigo-500" />
            Your Reasoning (Required)
          </label>
          <p className="text-xs text-slate-500 mb-3">Explain the steps you took to arrive at your answer. Correct reasoning earns 50% of the score!</p>
          <textarea
            value={currentReason}
            onChange={(e) => onReasonChange(e.target.value)}
            placeholder="Type your mathematical reasoning here..."
            className="w-full h-32 p-4 rounded-xl border border-slate-200 focus:border-indigo-500 focus:ring-2 focus:ring-indigo-200 focus:outline-none transition-all resize-none text-slate-700 placeholder-slate-400 bg-slate-50 focus:bg-white"
          />
        </div>

        {/* Action Bar */}
        <div className="flex flex-col-reverse md:flex-row items-center justify-between pt-6 border-t border-slate-100 gap-4">
          <div className="flex gap-2 w-full md:w-auto">
             <button 
              onClick={onPrev}
              disabled={questionIndex === 0}
              className={`flex items-center justify-center px-4 py-2.5 rounded-lg text-sm font-medium w-full md:w-auto
                ${questionIndex === 0 
                  ? 'text-slate-300 cursor-not-allowed bg-slate-50' 
                  : 'text-slate-600 bg-white border border-slate-200 hover:bg-slate-50 hover:text-slate-900'
                }
              `}
            >
              <Icons.ChevronLeft className="w-4 h-4 mr-1" />
              Previous
            </button>
            <button
              onClick={onSave}
              className="flex items-center justify-center px-4 py-2.5 rounded-lg text-sm font-medium text-slate-600 bg-white border border-slate-200 hover:bg-slate-50 hover:text-slate-900 w-full md:w-auto transition-colors"
            >
              <Icons.Save className="w-4 h-4 mr-1" />
              Save
            </button>
          </div>

          <button 
            onClick={onNext}
            disabled={!currentSelection || !currentReason.trim()}
            className={`flex items-center justify-center px-8 py-2.5 rounded-lg text-sm font-bold shadow-lg shadow-indigo-200 w-full md:w-auto transition-all transform hover:-translate-y-0.5
              ${(!currentSelection || !currentReason.trim())
                ? 'bg-slate-200 text-slate-400 cursor-not-allowed shadow-none'
                : 'bg-indigo-600 text-white hover:bg-indigo-700 hover:shadow-indigo-300'
              }
            `}
          >
            {questionIndex === totalQuestions - 1 ? 'Submit Quiz' : 'Next Question'}
            {questionIndex !== totalQuestions - 1 && <Icons.ChevronRight className="w-4 h-4 ml-1" />}
          </button>
        </div>
      </div>
    </div>
  );
};

export default QuizCard;

import React from 'react';
import { QuizResult, Question, UserResponse } from '../types';
import { Icons } from '../constants';

interface ResultsViewProps {
  result: QuizResult;
  questions: Question[];
  userResponses: UserResponse[];
  onRestart: () => void;
}

const ResultsView: React.FC<ResultsViewProps> = ({ result, questions, userResponses, onRestart }) => {
  const percentage = Math.round((result.totalScore / result.maxScore) * 100);

  // Determine Grade Color
  let gradeColor = "text-red-600";
  let gradeBg = "bg-red-50 border-red-200";
  if (percentage >= 80) {
    gradeColor = "text-green-600";
    gradeBg = "bg-green-50 border-green-200";
  } else if (percentage >= 50) {
    gradeColor = "text-amber-600";
    gradeBg = "bg-amber-50 border-amber-200";
  }

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-fade-in-up">
      {/* Summary Card */}
      <div className={`p-8 rounded-2xl border-2 ${gradeBg} flex flex-col md:flex-row items-center justify-between shadow-sm`}>
        <div className="mb-6 md:mb-0 text-center md:text-left">
          <h2 className={`text-3xl font-bold ${gradeColor} mb-2`}>Quiz Complete!</h2>
          <p className="text-slate-700 text-lg">{result.summary}</p>
        </div>
        <div className="flex flex-col items-center justify-center bg-white p-6 rounded-2xl shadow-sm border border-slate-100 min-w-[200px]">
          <span className="text-sm text-slate-500 uppercase tracking-wider font-semibold mb-1">Total Score</span>
          <span className={`text-5xl font-black ${gradeColor}`}>
            {result.totalScore}<span className="text-2xl text-slate-400">/{result.maxScore}</span>
          </span>
          <span className="text-sm font-medium text-slate-500 mt-2">{percentage}% Accuracy</span>
        </div>
      </div>

      {/* Questions Breakdown */}
      <div className="space-y-6">
        <h3 className="text-xl font-bold text-slate-800 px-2">Detailed Breakdown</h3>
        {result.evaluations.map((evaluation, idx) => {
          const question = questions.find(q => q.id === evaluation.questionId);
          const userResp = userResponses.find(r => r.questionId === evaluation.questionId);
          const option = question?.options.find(o => o.id === userResp?.selectedOptionId);
          const correctOption = question?.options.find(o => o.id === evaluation.correctOptionId);

          if (!question) return null;

          return (
            <div key={idx} className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
              {/* Question Header */}
              <div className="bg-slate-50 px-6 py-4 border-b border-slate-100 flex justify-between items-start">
                <div>
                    <span className="text-xs font-bold text-slate-500 uppercase tracking-wide">Question {idx + 1}</span>
                    <h4 className="text-lg font-semibold text-slate-900 mt-1">{question.text}</h4>
                </div>
                <div className="flex items-center space-x-4">
                     <div className="flex flex-col items-end">
                        <span className="text-xs text-slate-400">Answer</span>
                        <span className={`font-bold ${evaluation.answerScore > 0 ? 'text-green-600' : 'text-red-500'}`}>
                            {evaluation.answerScore}/5
                        </span>
                     </div>
                     <div className="flex flex-col items-end">
                        <span className="text-xs text-slate-400">Logic</span>
                        <span className={`font-bold ${evaluation.reasonScore >= 4 ? 'text-green-600' : evaluation.reasonScore >= 2 ? 'text-amber-500' : 'text-red-500'}`}>
                            {evaluation.reasonScore}/5
                        </span>
                     </div>
                </div>
              </div>

              <div className="p-6 grid grid-cols-1 md:grid-cols-2 gap-8">
                {/* User Side */}
                <div className="space-y-4">
                  <div>
                    <span className="text-xs font-semibold text-slate-400 uppercase">Your Answer</span>
                    <div className={`mt-1 p-3 rounded-lg border flex items-center ${
                      evaluation.isAnswerCorrect 
                        ? 'bg-green-50 border-green-200 text-green-900' 
                        : 'bg-red-50 border-red-200 text-red-900'
                    }`}>
                       {evaluation.isAnswerCorrect ? <Icons.CheckCircle className="w-5 h-5 mr-2" /> : <Icons.XCircle className="w-5 h-5 mr-2" />}
                       <span className="font-medium">{option?.text || "No selection"}</span>
                    </div>
                  </div>

                  <div>
                    <span className="text-xs font-semibold text-slate-400 uppercase">Your Reasoning</span>
                    <div className="mt-1 p-3 rounded-lg border border-slate-200 bg-slate-50 text-slate-700 text-sm italic">
                      "{userResp?.reasoning}"
                    </div>
                  </div>
                </div>

                {/* AI Feedback Side */}
                <div className="space-y-4 relative">
                    <div className="absolute left-0 top-0 bottom-0 w-px bg-slate-100 -ml-4 hidden md:block"></div>

                  {!evaluation.isAnswerCorrect && (
                     <div>
                        <span className="text-xs font-semibold text-slate-400 uppercase">Correct Answer</span>
                        <div className="mt-1 p-3 rounded-lg border border-indigo-100 bg-indigo-50 text-indigo-900 flex items-center">
                            <Icons.CheckCircle className="w-5 h-5 mr-2 text-indigo-600" />
                            <span className="font-medium">{correctOption?.text}</span>
                        </div>
                    </div>
                  )}

                  <div>
                     <span className="text-xs font-semibold text-slate-400 uppercase">Feedback on Reasoning</span>
                     <div className="mt-1 text-sm text-slate-700 leading-relaxed">
                        <p className="mb-2"><span className="font-semibold text-indigo-600">AI Evaluation:</span> {evaluation.reasonFeedback}</p>
                        <div className="p-3 bg-yellow-50 border border-yellow-100 rounded-lg text-yellow-900 text-xs mt-2">
                            <span className="font-bold block mb-1">Optimal Reasoning:</span>
                            {evaluation.correctReasoning}
                        </div>
                     </div>
                  </div>
                </div>
              </div>
            </div>
          );
        })}
      </div>

      <div className="flex justify-center pt-8 pb-12">
        <button 
            onClick={onRestart}
            className="flex items-center px-8 py-3 bg-indigo-600 text-white rounded-full font-bold shadow-lg hover:bg-indigo-700 hover:shadow-indigo-300 transition-all transform hover:-translate-y-1"
        >
            <Icons.RefreshCw className="w-5 h-5 mr-2" />
            Take Another Quiz
        </button>
      </div>
    </div>
  );
};

export default ResultsView;

