export default QuizSetup;

import React, { useState, useEffect } from 'react';
import { AppState, Question, UserResponse, QuizResult } from './types';
import { generateQuiz, evaluateQuiz } from './services/geminiService';
import QuizSetup from './components/QuizSetup';
import QuizCard from './components/QuizCard';
import ResultsView from './components/ResultsView';
import LoadingSpinner from './components/LoadingSpinner';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.WELCOME);
  const [questions, setQuestions] = useState<Question[]>([]);
  const [userResponses, setUserResponses] = useState<UserResponse[]>([]);
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [quizResult, setQuizResult] = useState<QuizResult | null>(null);
  const [errorMsg, setErrorMsg] = useState<string>("");

  const handleStartQuiz = async (topic: string, difficulty: string) => {
    setAppState(AppState.GENERATING);
    setErrorMsg("");
    try {
      // In a real app, number of questions could be dynamic. Fixed to 5 as per prompt suggestion.
      const generatedQuestions = await generateQuiz(topic, difficulty, 5);
      setQuestions(generatedQuestions);
      // Initialize empty responses
      setUserResponses(generatedQuestions.map(q => ({
        questionId: q.id,
        selectedOptionId: "",
        reasoning: ""
      })));
      setAppState(AppState.QUIZ);
    } catch (err) {
      console.error(err);
      setErrorMsg("Failed to generate quiz. Please check your API Key or try again.");
      setAppState(AppState.ERROR);
    }
  };

  const handleOptionSelect = (optionId: string) => {
    const updatedResponses = [...userResponses];
    updatedResponses[currentQuestionIndex].selectedOptionId = optionId;
    setUserResponses(updatedResponses);
  };

  const handleReasonChange = (reason: string) => {
    const updatedResponses = [...userResponses];
    updatedResponses[currentQuestionIndex].reasoning = reason;
    setUserResponses(updatedResponses);
  };

  const handleNext = () => {
    if (currentQuestionIndex < questions.length - 1) {
      setCurrentQuestionIndex(prev => prev + 1);
    } else {
      submitQuiz();
    }
  };

  const handlePrev = () => {
    if (currentQuestionIndex > 0) {
      setCurrentQuestionIndex(prev => prev - 1);
    }
  };

  const handleSave = () => {
    // In a persistent app, this would save to local storage or backend.
    // For this demo, state is already preserved in React state.
    // We'll just show a visual confirmation maybe?
    // For now, no-op is fine as React state holds it.
    alert("Progress saved temporarily!");
  };

  const submitQuiz = async () => {
    setAppState(AppState.SUBMITTING);
    try {
      const result = await evaluateQuiz(questions, userResponses);
      setQuizResult(result);
      setAppState(AppState.RESULTS);
    } catch (err) {
      console.error(err);
      setErrorMsg("Failed to evaluate quiz. Please try again.");
      setAppState(AppState.ERROR);
    }
  };

  const handleRestart = () => {
    setAppState(AppState.WELCOME);
    setQuestions([]);
    setUserResponses([]);
    setCurrentQuestionIndex(0);
    setQuizResult(null);
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
           <div className="font-bold text-xl text-slate-900 tracking-tight flex items-center">
             <span className="text-indigo-600 mr-1">Reason</span>Math
           </div>
           {appState === AppState.QUIZ && (
             <div className="text-sm font-medium text-slate-500">
               Question {currentQuestionIndex + 1} / {questions.length}
             </div>
           )}
        </div>
      </header>

      <main className="flex-grow p-4 md:p-8">
        {appState === AppState.WELCOME && (
          <div className="h-full flex items-center justify-center">
            <QuizSetup onStart={handleStartQuiz} />
          </div>
        )}

        {appState === AppState.GENERATING && (
          <div className="h-full flex items-center justify-center">
            <LoadingSpinner message="AI is crafting your questions..." />
          </div>
        )}

        {appState === AppState.QUIZ && questions.length > 0 && (
          <QuizCard 
            question={questions[currentQuestionIndex]}
            response={userResponses[currentQuestionIndex]}
            onOptionSelect={handleOptionSelect}
            onReasonChange={handleReasonChange}
            questionIndex={currentQuestionIndex}
            totalQuestions={questions.length}
            onNext={handleNext}
            onPrev={handlePrev}
            onSave={handleSave}
          />
        )}

        {appState === AppState.SUBMITTING && (
           <div className="h-full flex items-center justify-center">
             <LoadingSpinner message="AI is grading your answers and reasoning..." />
           </div>
        )}

        {appState === AppState.RESULTS && quizResult && (
          <ResultsView 
            result={quizResult} 
            questions={questions} 
            userResponses={userResponses} 
            onRestart={handleRestart}
          />
        )}

        {appState === AppState.ERROR && (
          <div className="max-w-md mx-auto mt-10 bg-white p-6 rounded-lg shadow-lg border-l-4 border-red-500">
            <h3 className="text-lg font-bold text-red-600 mb-2">Error</h3>
            <p className="text-slate-600 mb-4">{errorMsg}</p>
            <button 
              onClick={handleRestart}
              className="px-4 py-2 bg-slate-800 text-white rounded hover:bg-slate-700"
            >
              Try Again
            </button>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

