import React from 'react';

interface QuestionNavigationProps {
  totalQuestions: number;
  currentQuestionIndex: number;
  visitedIndices: Set<number>;
  markedIndices: Set<number>;
  userResponses: { [key: number]: boolean }; // Map index to whether it has an answer
  onNavigate: (index: number) => void;
  onSubmit: () => void;
}

const QuestionNavigation: React.FC<QuestionNavigationProps> = ({
  totalQuestions,
  currentQuestionIndex,
  visitedIndices,
  markedIndices,
  userResponses,
  onNavigate,
  onSubmit
}) => {
  return (
    <div className="bg-white rounded-2xl shadow-lg border border-slate-100 p-4 flex flex-col h-full">
      <h3 className="text-lg font-bold text-slate-800 mb-4 px-1">Question Palette</h3>

      <div className="flex-grow">
        <div className="grid grid-cols-4 sm:grid-cols-5 gap-2 md:gap-3">
          {Array.from({ length: totalQuestions }).map((_, idx) => {
            const isAnswered = userResponses[idx];
            const isVisited = visitedIndices.has(idx);
            const isMarked = markedIndices.has(idx);
            const isCurrent = currentQuestionIndex === idx;

            let bgColor = "bg-slate-100 text-slate-500"; // Default Not Visited (Grey)
            let borderColor = "border-slate-200";

            if (isMarked) {
                bgColor = "bg-orange-100 text-orange-700"; // Marked (Orange)
                borderColor = "border-orange-300";
            } else if (isAnswered) {
                bgColor = "bg-green-100 text-green-700"; // Answered (Green)
                borderColor = "border-green-300";
            } else if (isVisited) {
                bgColor = "bg-red-50 text-red-600"; // Visited but not Answered (Red)
                borderColor = "border-red-200";
            }

            if (isCurrent) {
                borderColor = "border-indigo-600 ring-2 ring-indigo-200";
            }

            return (
              <button
                key={idx}
                onClick={() => onNavigate(idx)}
                className={`
                  w-10 h-10 md:w-12 md:h-12 rounded-lg font-bold text-sm border-2 transition-all flex items-center justify-center
                  ${bgColor} ${borderColor} hover:opacity-80
                `}
              >
                {idx + 1}
              </button>
            );
          })}
        </div>
      </div>

      <div className="mt-6 border-t border-slate-100 pt-4 space-y-2 text-xs text-slate-500">
        <div className="flex items-center"><div className="w-3 h-3 bg-green-100 border border-green-300 rounded mr-2"></div> Answered</div>
        <div className="flex items-center"><div className="w-3 h-3 bg-red-50 border border-red-200 rounded mr-2"></div> Not Answered</div>
        <div className="flex items-center"><div className="w-3 h-3 bg-orange-100 border border-orange-300 rounded mr-2"></div> Marked for Review</div>
        <div className="flex items-center"><div className="w-3 h-3 bg-slate-100 border border-slate-200 rounded mr-2"></div> Not Visited</div>
      </div>

      <button
        onClick={onSubmit}
        className="w-full mt-6 py-3 bg-indigo-600 text-white font-bold rounded-xl shadow-lg hover:bg-indigo-700 transition-colors"
      >
        Submit Quiz
      </button>
    </div>
  );
};

