import React, { useState, useEffect } from 'react';
import { AppState, Question, UserResponse, QuizResult, MarkingScheme, QuizConfig } from './types';
import { generateQuiz, evaluateQuiz } from './services/geminiService';
import QuizSetup from './components/QuizSetup';
import QuizCard from './components/QuizCard';
import ResultsView from './components/ResultsView';
import LoadingSpinner from './components/LoadingSpinner';
import MindGradeLogo from './components/MindGradeLogo';
import QuestionNavigation from './components/QuestionNavigation';
import { Icons } from './constants';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.WELCOME);
  const [questions, setQuestions] = useState<Question[]>([]);
  const [userResponses, setUserResponses] = useState<UserResponse[]>([]);
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [quizResult, setQuizResult] = useState<QuizResult | null>(null);
  const [errorMsg, setErrorMsg] = useState<string>("");
  const [markingScheme, setMarkingScheme] = useState<MarkingScheme>({ answerPoints: 5, reasonPoints: 5 });

  // New States
  const [timeLeft, setTimeLeft] = useState<number>(0);
  const [visitedIndices, setVisitedIndices] = useState<Set<number>>(new Set([0]));
  const [markedIndices, setMarkedIndices] = useState<Set<number>>(new Set());

  // Timer Effect
  useEffect(() => {
    let timer: number;
    if (appState === AppState.QUIZ && timeLeft > 0) {
      timer = window.setInterval(() => {
        setTimeLeft((prev) => {
          if (prev <= 1) {
            clearInterval(timer);
            submitQuiz(); // Auto submit
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
    }
    return () => clearInterval(timer);
  }, [appState, timeLeft]);

  const handleStartAI = async (config: QuizConfig) => {
    setMarkingScheme(config.markingScheme);
    setAppState(AppState.GENERATING);
    setErrorMsg("");
    try {
      const generatedQuestions = await generateQuiz(config.topic, config.difficulty, config.questionCount);
      setQuestions(generatedQuestions);
      initializeQuiz(generatedQuestions, config.timeLimit);
    } catch (err) {
      console.error(err);
      setErrorMsg("Failed to generate quiz. Please check your API Key or try again.");
      setAppState(AppState.ERROR);
    }
  };

  const handleStartManual = (manualQuestions: Question[], scheme: MarkingScheme, limit: number) => {
    setMarkingScheme(scheme);
    setQuestions(manualQuestions);
    initializeQuiz(manualQuestions, limit);
  };

  const initializeQuiz = (qs: Question[], minutes: number) => {
    setUserResponses(qs.map(q => ({
        questionId: q.id,
        selectedOptionId: "",
        reasoning: ""
      })));
    setTimeLeft(minutes * 60);
    setVisitedIndices(new Set([0]));
    setMarkedIndices(new Set());
    setCurrentQuestionIndex(0);
    setAppState(AppState.QUIZ);
  };

  const handleOptionSelect = (optionId: string) => {
    const updatedResponses = [...userResponses];
    updatedResponses[currentQuestionIndex].selectedOptionId = optionId;
    setUserResponses(updatedResponses);
  };

  const handleReasonChange = (reason: string) => {
    const updatedResponses = [...userResponses];
    updatedResponses[currentQuestionIndex].reasoning = reason;
    setUserResponses(updatedResponses);
  };

  const markVisited = (idx: number) => {
    setVisitedIndices(prev => new Set(prev).add(idx));
  };

  const handleNext = () => {
    if (currentQuestionIndex < questions.length - 1) {
      const nextIdx = currentQuestionIndex + 1;
      setCurrentQuestionIndex(nextIdx);
      markVisited(nextIdx);
    } else {
      submitQuiz();
    }
  };

  const handlePrev = () => {
    if (currentQuestionIndex > 0) {
      const prevIdx = currentQuestionIndex - 1;
      setCurrentQuestionIndex(prevIdx);
      markVisited(prevIdx);
    }
  };

  const handleNavigate = (index: number) => {
    setCurrentQuestionIndex(index);
    markVisited(index);
  };

  const handleToggleMark = () => {
    setMarkedIndices(prev => {
        const next = new Set(prev);
        if (next.has(currentQuestionIndex)) {
            next.delete(currentQuestionIndex);
        } else {
            next.add(currentQuestionIndex);
        }
        return next;
    });
  };

  const submitQuiz = async () => {
    setAppState(AppState.SUBMITTING);
    try {
      const result = await evaluateQuiz(questions, userResponses, markingScheme);
      setQuizResult(result);
      setAppState(AppState.RESULTS);
    } catch (err) {
      console.error(err);
      setErrorMsg("Failed to evaluate quiz. Please try again.");
      setAppState(AppState.ERROR);
    }
  };

  const handleRestart = () => {
    setAppState(AppState.WELCOME);
    setQuestions([]);
    setUserResponses([]);
    setCurrentQuestionIndex(0);
    setQuizResult(null);
  };

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m}:${s < 10 ? '0' : ''}${s}`;
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-20 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
           <div className="font-bold text-xl text-slate-900 tracking-tight flex items-center group cursor-pointer" onClick={handleRestart}>
             <div className="w-8 h-8 mr-2">
                <MindGradeLogo />
             </div>
             <span className="text-transparent bg-clip-text bg-gradient-to-r from-indigo-600 to-purple-600">MindGrade</span>
           </div>

           {appState === AppState.QUIZ && (
             <div className="flex items-center gap-4">
                 <div className={`flex items-center font-mono font-bold text-lg px-3 py-1 rounded-lg ${timeLeft < 60 ? 'bg-red-100 text-red-600 animate-pulse' : 'bg-slate-100 text-slate-700'}`}>
                    <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="mr-2"><circle cx="12" cy="12" r="10"></circle><polyline points="12 6 12 12 16 14"></polyline></svg>
                    {formatTime(timeLeft)}
                 </div>
                 {/* Mobile menu could go here, but for now we focus on desktop layout */}
             </div>
           )}
        </div>
      </header>

      <main className="flex-grow p-4 md:p-6 lg:p-8 max-w-7xl mx-auto w-full">
        {appState === AppState.WELCOME && (
          <div className="h-full flex items-center justify-center">
            <QuizSetup onStartAI={handleStartAI} onStartManual={handleStartManual} />
          </div>
        )}

        {appState === AppState.GENERATING && (
          <div className="h-full flex items-center justify-center">
            <LoadingSpinner message="AI is generating high-quality questions..." />
          </div>
        )}

        {appState === AppState.QUIZ && questions.length > 0 && (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 h-[calc(100vh-140px)]">
             {/* Left Column: Quiz Card */}
             <div className="lg:col-span-8 h-full">
                <QuizCard 
                    question={questions[currentQuestionIndex]}
                    response={userResponses[currentQuestionIndex]}
                    onOptionSelect={handleOptionSelect}
                    onReasonChange={handleReasonChange}
                    questionIndex={currentQuestionIndex}
                    totalQuestions={questions.length}
                    onNext={handleNext}
                    onPrev={handlePrev}
                    isMarked={markedIndices.has(currentQuestionIndex)}
                    onToggleMark={handleToggleMark}
                />
             </div>

             {/* Right Column: Navigation */}
             <div className="lg:col-span-4 h-full hidden lg:block overflow-y-auto">
                <QuestionNavigation 
                    totalQuestions={questions.length}
                    currentQuestionIndex={currentQuestionIndex}
                    visitedIndices={visitedIndices}
                    markedIndices={markedIndices}
                    userResponses={userResponses.reduce((acc, curr, idx) => ({ ...acc, [idx]: !!curr.selectedOptionId }), {})}
                    onNavigate={handleNavigate}
                    onSubmit={submitQuiz}
                />
             </div>

             {/* Mobile Navigation (Simple fallback for small screens, usually a drawer, but putting below for simplicity) */}
             <div className="lg:hidden">
                 <QuestionNavigation 
                    totalQuestions={questions.length}
                    currentQuestionIndex={currentQuestionIndex}
                    visitedIndices={visitedIndices}
                    markedIndices={markedIndices}
                    userResponses={userResponses.reduce((acc, curr, idx) => ({ ...acc, [idx]: !!curr.selectedOptionId }), {})}
                    onNavigate={handleNavigate}
                    onSubmit={submitQuiz}
                />
             </div>
          </div>
        )}

        {appState === AppState.SUBMITTING && (
           <div className="h-full flex items-center justify-center">
             <LoadingSpinner message="Evaluating your answers and logic..." />
           </div>
        )}

        {appState === AppState.RESULTS && quizResult && (
          <ResultsView 
            result={quizResult} 
            questions={questions} 
            userResponses={userResponses} 
            onRestart={handleRestart}
          />
        )}

        {appState === AppState.ERROR && (
          <div className="max-w-md mx-auto mt-10 bg-white p-6 rounded-lg shadow-lg border-l-4 border-red-500">
            <h3 className="text-lg font-bold text-red-600 mb-2">Error</h3>
            <p className="text-slate-600 mb-4">{errorMsg}</p>
            <button 
              onClick={handleRestart}
              className="px-4 py-2 bg-slate-800 text-white rounded hover:bg-slate-700"
            >
              Try Again
            </button>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useEffect, useRef } from 'react';

declare global {
  interface Window {
    MathJax: any;
  }
}

interface MathRendererProps {
  text: string;
  className?: string;
  inline?: boolean;
}

const MathRenderer: React.FC<MathRendererProps> = ({ text, className = "", inline = false }) => {
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const renderMath = async () => {
      if (window.MathJax && ref.current) {
        // 1. Reset content to raw text first
        ref.current.innerHTML = text;

        // 2. Clear previous MathJax formatting if any (though innerHTML reset usually handles it)
        // 3. Queue typeset
        try {
           await window.MathJax.typesetPromise([ref.current]);
        } catch (err) {
           console.warn('MathJax typesetting failed:', err);
           // Fallback: just leave text as is, user might see raw $ but app won't crash
        }
      }
    };

    renderMath();
  }, [text]);

  const Tag = inline ? 'span' : 'div';

  return (
    <Tag 
      ref={ref} 
      className={`math-content ${className} text-slate-800`} 
    />
  );
};

export default MathRenderer;

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { Question, UserResponse, QuizResult, MarkingScheme } from "../types";

// NOTE: In a real app, API_KEY should be handled securely. 
// For this frontend-only demo, we expect it in process.env.
const apiKey = process.env.API_KEY || '';

const ai = new GoogleGenAI({ apiKey });

const QUIZ_SCHEMA: Schema = {
  type: Type.ARRAY,
  items: {
    type: Type.OBJECT,
    properties: {
      id: { type: Type.STRING },
      text: { type: Type.STRING },
      options: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            id: { type: Type.STRING },
            text: { type: Type.STRING }
          },
          required: ["id", "text"]
        }
      },
      correctOptionId: { type: Type.STRING },
      correctReasoning: { type: Type.STRING }
    },
    required: ["id", "text", "options", "correctOptionId", "correctReasoning"]
  }
};

const EVALUATION_SCHEMA: Schema = {
  type: Type.OBJECT,
  properties: {
    evaluations: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          questionId: { type: Type.STRING },
          answerScore: { type: Type.NUMBER, description: "Points awarded for correct option" },
          reasonScore: { type: Type.NUMBER, description: "Points awarded for reasoning" },
          totalScore: { type: Type.NUMBER },
          isAnswerCorrect: { type: Type.BOOLEAN },
          reasonFeedback: { type: Type.STRING },
          correctReasoning: { type: Type.STRING },
          correctOptionId: { type: Type.STRING }
        },
        required: ["questionId", "answerScore", "reasonScore", "totalScore", "isAnswerCorrect", "reasonFeedback", "correctReasoning", "correctOptionId"]
      }
    },
    totalScore: { type: Type.NUMBER },
    maxScore: { type: Type.NUMBER },
    summary: { type: Type.STRING }
  },
  required: ["evaluations", "totalScore", "maxScore", "summary"]
};

export const generateQuiz = async (topic: string, difficulty: string, count: number = 5): Promise<Question[]> => {
  const model = "gemini-2.5-flash";

  const prompt = `
    Generate ${count} multiple-choice questions on the topic of "${topic}" with "${difficulty}" difficulty.
    For each question, provide 4 options. 
    One option must be correct.
    Provide the ID of the correct option and a detailed explanation of the logic/proof as 'correctReasoning'.

    IMPORTANT LATEX RULES FOR JSON:
    1. You must output valid JSON.
    2. For math expressions, use standard LaTeX enclosed in single dollar signs like $ x^2 $.
    3. CRITICAL: Because this is a JSON string, all backslashes in LaTeX must be double-escaped. 
       - Correct: "Calculate $\\\\frac{1}{2}$" (becomes \frac in string)
       - Incorrect: "Calculate $\frac{1}{2}$" (invalid JSON escape)
       - Correct: "Solve for $x$: $3x + 5 = 0$"
    4. Do not use plain text for math symbols if LaTeX is cleaner.
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: QUIZ_SCHEMA,
        systemInstruction: "You are a rigorous mathematics teacher. You output strictly compliant JSON with double-escaped LaTeX backslashes."
      }
    });

    const text = response.text;
    if (!text) throw new Error("No content generated");

    return JSON.parse(text) as Question[];
  } catch (error) {
    console.error("Quiz Generation Error:", error);
    throw error;
  }
};

export const evaluateQuiz = async (
  questions: Question[], 
  userResponses: UserResponse[],
  markingScheme: MarkingScheme
): Promise<QuizResult> => {
  const model = "gemini-2.5-flash";

  // Prepare a prompt that includes both the original questions (with truth) and user answers
  const dataForAI = questions.map(q => {
    const userResp = userResponses.find(ur => ur.questionId === q.id);
    return {
      questionId: q.id,
      questionText: q.text,
      options: q.options,
      correctOptionId: q.correctOptionId,
      goldenReasoning: q.correctReasoning,
      userSelectedOptionId: userResp?.selectedOptionId || "NO_ANSWER",
      userReasoning: userResp?.reasoning || "NO_REASONING"
    };
  });

  const prompt = `
    Evaluate the following student responses.

    Scoring Rules:
    1. Answer Score: Max ${markingScheme.answerPoints} points. Give full ${markingScheme.answerPoints} points if 'userSelectedOptionId' matches 'correctOptionId', else 0.
    2. Reason Score: Max ${markingScheme.reasonPoints} points. Evaluate 'userReasoning'. 
       - If reasoning implies correct steps/logic, give high/full marks.
       - If flawed but answer is correct by luck, give low marks.
       - If non-existent, give 0.
       - Use a scale from 0 to ${markingScheme.reasonPoints}.

    Provide helpful feedback in 'reasonFeedback'. Use LaTeX ($...$) for math in feedback, double-escaping backslashes for JSON (e.g. \\\\frac).

    Data to evaluate:
    ${JSON.stringify(dataForAI, null, 2)}
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: EVALUATION_SCHEMA,
        systemInstruction: "You are a fair but strict grader. Output valid JSON."
      }
    });

    const text = response.text;
    if (!text) throw new Error("No evaluation generated");

    return JSON.parse(text) as QuizResult;
  } catch (error) {
    console.error("Evaluation Error:", error);
    throw error;
  }
};

import React from 'react';
import { Icons } from '../constants';

interface QuestionNavigationProps {
  totalQuestions: number;
  currentQuestionIndex: number;
  visitedIndices: Set<number>;
  markedIndices: Set<number>;
  userResponses: { [key: number]: boolean }; 
  onNavigate: (index: number) => void;
  onSubmit: () => void;
}

const QuestionNavigation: React.FC<QuestionNavigationProps> = ({
  totalQuestions,
  currentQuestionIndex,
  visitedIndices,
  markedIndices,
  userResponses,
  onNavigate,
  onSubmit
}) => {
  const answeredCount = Object.values(userResponses).filter(Boolean).length;
  const markedCount = markedIndices.size;
  const notVisitedCount = totalQuestions - visitedIndices.size;

  return (
    <div className="bg-white h-full flex flex-col border-l border-slate-200 shadow-xl z-20">
      {/* Header */}
      <div className="p-4 bg-slate-100 border-b border-slate-200">
         <h3 className="font-bold text-slate-800 flex items-center">
            <Icons.BrainCircuit className="w-5 h-5 mr-2 text-indigo-600" />
            Question Palette
         </h3>
      </div>

      {/* Legend - Compact */}
      <div className="p-4 grid grid-cols-2 gap-2 text-[10px] md:text-xs text-slate-600 border-b border-slate-100 bg-white">
        <div className="flex items-center">
             <div className="w-3 h-3 bg-green-500 rounded-sm mr-1.5 shadow-sm"></div>
             <span>Answered ({answeredCount})</span>
        </div>
        <div className="flex items-center">
             <div className="w-3 h-3 bg-red-500 rounded-sm mr-1.5 shadow-sm"></div>
             <span>Not Answered</span>
        </div>
        <div className="flex items-center">
             <div className="w-3 h-3 bg-orange-400 rounded-full mr-1.5 shadow-sm"></div>
             <span>Review ({markedCount})</span>
        </div>
        <div className="flex items-center">
             <div className="w-3 h-3 bg-slate-200 rounded-sm mr-1.5 shadow-sm"></div>
             <span>Not Visited ({notVisitedCount})</span>
        </div>
      </div>

      {/* Grid */}
      <div className="flex-grow overflow-y-auto p-4 custom-scrollbar bg-slate-50">
        <div className="grid grid-cols-4 gap-3 content-start">
          {Array.from({ length: totalQuestions }).map((_, idx) => {
            const isAnswered = userResponses[idx];
            const isVisited = visitedIndices.has(idx);
            const isMarked = markedIndices.has(idx);
            const isCurrent = currentQuestionIndex === idx;

            // CBT Style Coloring logic
            let bgClass = "bg-slate-200 text-slate-600 border-slate-300"; // Default Not Visited (Grey)

            if (isAnswered) {
                bgClass = "bg-green-500 text-white border-green-600 shadow-sm"; // Answered (Green)
            } else if (isVisited) {
                bgClass = "bg-red-500 text-white border-red-600 shadow-sm"; // Visited (Red)
            }

            // Mark overrides color shape in some systems, here we stick to color but add a ring
            if (isMarked) {
               // Usually marked is purple or orange. Let's use Orange circle style or overlay.
               // If answered and marked -> Green with orange ring? 
               // Let's prioritize Marked status visually for the "Marked" requirement
               if (!isAnswered) {
                  bgClass = "bg-orange-400 text-white border-orange-500 shadow-sm";
               }
            }

            const currentRing = isCurrent ? "ring-2 ring-indigo-600 ring-offset-2 z-10 scale-105" : "";
            const markedIndicator = isMarked && isAnswered ? (
                <div className="absolute -top-1 -right-1 w-3 h-3 bg-orange-400 rounded-full border-2 border-white"></div>
            ) : null;

            return (
              <button
                key={idx}
                onClick={() => onNavigate(idx)}
                className={`
                  relative h-10 w-full rounded-md font-bold text-sm border transition-all flex items-center justify-center
                  ${bgClass} ${currentRing} hover:opacity-90
                `}
              >
                {idx + 1}
                {markedIndicator}
              </button>
            );
          })}
        </div>
      </div>

      {/* Footer Actions */}
      <div className="p-4 bg-white border-t border-slate-200 shadow-[-5px_0_15px_rgba(0,0,0,0.05)]">
        <button
          onClick={onSubmit}
          className="w-full py-3 bg-indigo-600 text-white font-bold rounded-lg shadow-lg hover:bg-indigo-700 active:scale-95 transition-all flex items-center justify-center"
        >
          Submit Test
        </button>
      </div>
    </div>
  );
};

