                onClick={handleRestart}
                className="px-4 py-2 bg-slate-800 text-white rounded hover:bg-slate-700 w-full font-bold"
                >
                Try Again
                </button>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

