import React, { useEffect, useRef } from 'react';

declare global {
  interface Window {
    MathJax: any;
  }
}

interface MathRendererProps {
  text: string;
  className?: string;
  inline?: boolean;
}

const MathRenderer: React.FC<MathRendererProps> = ({ text, className = "", inline = false }) => {
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    let isMounted = true;

    const renderMath = async () => {
      if (window.MathJax && ref.current) {
        // Set content
        ref.current.innerHTML = text;

        try {
            // Ensure typeset is promised and handled
            // We use a small delay to ensure DOM is ready for MathJax in some edge cases
            await window.MathJax.typesetPromise([ref.current]);
        } catch (err) {
            console.debug('MathJax typesetting warning:', err);
            // If promise fails (e.g. typeset already running), clear and retry once might help, 
            // but usually safe to ignore as MathJax 3 handles queue internally largely.
            if (isMounted && window.MathJax.typesetClear) {
                try {
                    window.MathJax.typesetClear([ref.current]);
                    await window.MathJax.typesetPromise([ref.current]);
                } catch (e) { /* ignore retry failure */ }
            }
        }
      }
    };

    renderMath();

    return () => { isMounted = false; };
  }, [text]);

  const Tag = inline ? 'span' : 'div';

  return (
    <Tag 
      ref={ref} 
      className={`math-content ${className} text-inherit`} 
    />
  );
};

export default MathRenderer;

