    questionCount: 15,
    timeLimit: 40,
    markingScheme: { answerPoints: 4, reasonPoints: 4 }
  },
  {
    id: 'sat',
    name: 'SAT Math',
    description: 'Standardized test widely used for college admissions. Algebra and Problem Solving.',
