export enum AppState {
  HOME = 'HOME',
  WELCOME = 'WELCOME',
  GENERATING = 'GENERATING',
  QUIZ = 'QUIZ',
  SUBMITTING = 'SUBMITTING',
  RESULTS = 'RESULTS',
  ERROR = 'ERROR'
}

import React, { useState, useEffect } from 'react';
import { AppState, Question, UserResponse, QuizResult, MarkingScheme, QuizConfig } from './types';
import { generateQuiz, evaluateQuiz } from './services/geminiService';
import QuizSetup from './components/QuizSetup';
import QuizCard from './components/QuizCard';
import ResultsView from './components/ResultsView';
import LoadingSpinner from './components/LoadingSpinner';
import MindGradeLogo from './components/MindGradeLogo';
import QuestionNavigation from './components/QuestionNavigation';
import LandingPage from './components/LandingPage';
import { Icons } from './constants';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.HOME);
  const [questions, setQuestions] = useState<Question[]>([]);
  const [userResponses, setUserResponses] = useState<UserResponse[]>([]);
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [quizResult, setQuizResult] = useState<QuizResult | null>(null);
  const [errorMsg, setErrorMsg] = useState<string>("");
  const [markingScheme, setMarkingScheme] = useState<MarkingScheme>({ answerPoints: 5, reasonPoints: 5 });

  // New States
  const [timeLeft, setTimeLeft] = useState<number>(0);
  const [visitedIndices, setVisitedIndices] = useState<Set<number>>(new Set([0]));
  const [markedIndices, setMarkedIndices] = useState<Set<number>>(new Set());
  const [showMobileNav, setShowMobileNav] = useState(false);

  // Timer Effect
  useEffect(() => {
    let timer: number;
    if (appState === AppState.QUIZ && timeLeft > 0) {
      timer = window.setInterval(() => {
        setTimeLeft((prev) => {
          if (prev <= 1) {
            clearInterval(timer);
            submitQuiz(); // Auto submit
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
    }
    return () => clearInterval(timer);
  }, [appState, timeLeft]);

  const handleStartAI = async (config: QuizConfig) => {
    setMarkingScheme(config.markingScheme);
    setAppState(AppState.GENERATING);
    setErrorMsg("");
    try {
      const generatedQuestions = await generateQuiz(config.topic, config.difficulty, config.questionCount);
      setQuestions(generatedQuestions);
      initializeQuiz(generatedQuestions, config.timeLimit);
    } catch (err) {
      console.error(err);
      setErrorMsg("Failed to generate quiz. Please check your API Key or try again.");
      setAppState(AppState.ERROR);
    }
  };

  const handleStartManual = (manualQuestions: Question[], scheme: MarkingScheme, limit: number) => {
    setMarkingScheme(scheme);
    setQuestions(manualQuestions);
    initializeQuiz(manualQuestions, limit);
  };

  const initializeQuiz = (qs: Question[], minutes: number) => {
    setUserResponses(qs.map(q => ({
        questionId: q.id,
        selectedOptionId: "",
        reasoning: ""
      })));
    setTimeLeft(minutes * 60);
    setVisitedIndices(new Set([0]));
    setMarkedIndices(new Set());
    setCurrentQuestionIndex(0);
    setAppState(AppState.QUIZ);
  };

  const handleOptionSelect = (optionId: string) => {
    const updatedResponses = [...userResponses];
    updatedResponses[currentQuestionIndex].selectedOptionId = optionId;
    setUserResponses(updatedResponses);
  };

  const handleReasonChange = (reason: string) => {
    const updatedResponses = [...userResponses];
    updatedResponses[currentQuestionIndex].reasoning = reason;
    setUserResponses(updatedResponses);
  };

  const markVisited = (idx: number) => {
    setVisitedIndices(prev => new Set(prev).add(idx));
  };

  const handleNext = () => {
    if (currentQuestionIndex < questions.length - 1) {
      const nextIdx = currentQuestionIndex + 1;
      setCurrentQuestionIndex(nextIdx);
      markVisited(nextIdx);
    } else {
      submitQuiz();
    }
  };

  const handlePrev = () => {
    if (currentQuestionIndex > 0) {
      const prevIdx = currentQuestionIndex - 1;
      setCurrentQuestionIndex(prevIdx);
      markVisited(prevIdx);
    }
  };

  const handleNavigate = (index: number) => {
    setCurrentQuestionIndex(index);
    markVisited(index);
    setShowMobileNav(false);
  };

  const handleToggleMark = () => {
    setMarkedIndices(prev => {
        const next = new Set(prev);
        if (next.has(currentQuestionIndex)) {
            next.delete(currentQuestionIndex);
        } else {
            next.add(currentQuestionIndex);
        }
        return next;
    });
  };

  const submitQuiz = async () => {
    setAppState(AppState.SUBMITTING);
    try {
      const result = await evaluateQuiz(questions, userResponses, markingScheme);
      setQuizResult(result);
      setAppState(AppState.RESULTS);
    } catch (err) {
      console.error(err);
      setErrorMsg("Failed to evaluate quiz. Please try again.");
      setAppState(AppState.ERROR);
    }
  };

  const handleRestart = () => {
    setAppState(AppState.WELCOME);
    setQuestions([]);
    setUserResponses([]);
    setCurrentQuestionIndex(0);
    setQuizResult(null);
  };

  const handleGoHome = () => {
    setAppState(AppState.HOME);
    setQuestions([]);
    setUserResponses([]);
    setCurrentQuestionIndex(0);
    setQuizResult(null);
  };

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m}:${s < 10 ? '0' : ''}${s}`;
  };

  return (
    <div className="h-screen bg-slate-50 flex flex-col font-sans overflow-hidden">
      {appState !== AppState.HOME && (
        <header className="bg-white border-b border-slate-200 flex-none z-30 shadow-sm relative">
            <div className="w-full px-4 h-16 flex items-center justify-between">
            <div className="font-bold text-xl text-slate-900 tracking-tight flex items-center group cursor-pointer" onClick={handleGoHome}>
                <div className="w-8 h-8 mr-2">
                    <MindGradeLogo />
                </div>
                <span className="text-transparent bg-clip-text bg-gradient-to-r from-indigo-600 to-purple-600">MindGrade</span>
            </div>

            {appState === AppState.QUIZ && (
                <div className="flex items-center gap-4">
                    <div className={`flex items-center font-mono font-bold text-lg px-3 py-1.5 rounded-lg border-2 shadow-sm transition-all ${timeLeft < 60 ? 'bg-red-50 text-red-600 border-red-200 animate-pulse' : 'bg-white text-slate-700 border-slate-200'}`}>
                        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="mr-2"><circle cx="12" cy="12" r="10"></circle><polyline points="12 6 12 12 16 14"></polyline></svg>
                        {formatTime(timeLeft)}
                    </div>

                    <button 
                        onClick={() => setShowMobileNav(!showMobileNav)}
                        className="lg:hidden p-2 rounded-lg bg-slate-100 text-slate-600"
                    >
                        <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="3" y1="12" x2="21" y2="12"></line><line x1="3" y1="6" x2="21" y2="6"></line><line x1="3" y1="18" x2="21" y2="18"></line></svg>
                    </button>
                </div>
            )}
            </div>
        </header>
      )}

      <main className="flex-grow flex overflow-hidden relative">
        {appState === AppState.HOME && (
            <LandingPage onGetStarted={() => setAppState(AppState.WELCOME)} />
        )}

        {appState === AppState.WELCOME && (
          <div className="w-full h-full overflow-y-auto p-4 md:p-8 flex items-center justify-center bg-slate-50/50">
            <QuizSetup onStartAI={handleStartAI} onStartManual={handleStartManual} />
          </div>
        )}

        {appState === AppState.GENERATING && (
          <div className="w-full h-full flex items-center justify-center">
            <LoadingSpinner message="AI is crafting your exam paper..." />
          </div>
        )}

        {appState === AppState.QUIZ && questions.length > 0 && (
          <>
             {/* Left Column: Quiz Card - Takes available space */}
             <div className="flex-1 flex flex-col h-full overflow-hidden bg-slate-100">
                <QuizCard 
                    question={questions[currentQuestionIndex]}
                    response={userResponses[currentQuestionIndex]}
                    onOptionSelect={handleOptionSelect}
                    onReasonChange={handleReasonChange}
                    questionIndex={currentQuestionIndex}
                    totalQuestions={questions.length}
                    onNext={handleNext}
                    onPrev={handlePrev}
                    isMarked={markedIndices.has(currentQuestionIndex)}
                    onToggleMark={handleToggleMark}
                />
             </div>

             {/* Right Column: Navigation - Fixed Width */}
             <div className={`
                fixed inset-y-0 right-0 w-80 transform transition-transform duration-300 ease-in-out z-40 lg:relative lg:transform-none lg:w-80 flex-none
                ${showMobileNav ? 'translate-x-0' : 'translate-x-full lg:translate-x-0'}
             `}>
                <QuestionNavigation 
                    totalQuestions={questions.length}
                    currentQuestionIndex={currentQuestionIndex}
                    visitedIndices={visitedIndices}
                    markedIndices={markedIndices}
                    userResponses={userResponses.reduce((acc, curr, idx) => ({ ...acc, [idx]: !!curr.selectedOptionId }), {})}
                    onNavigate={handleNavigate}
                    onSubmit={submitQuiz}
                />
             </div>

             {/* Overlay for mobile nav */}
             {showMobileNav && (
                <div 
                    className="fixed inset-0 bg-black/50 z-30 lg:hidden"
                    onClick={() => setShowMobileNav(false)}
                />
             )}
          </>
        )}

        {appState === AppState.SUBMITTING && (
           <div className="w-full h-full flex items-center justify-center bg-white">
             <LoadingSpinner message="Grading in progress..." />
           </div>
        )}

        {appState === AppState.RESULTS && quizResult && (
          <div className="w-full h-full overflow-y-auto p-4 md:p-8 bg-slate-50">
             <ResultsView 
                result={quizResult} 
                questions={questions} 
                userResponses={userResponses} 
                onRestart={handleRestart}
            />
          </div>
        )}

        {appState === AppState.ERROR && (
          <div className="w-full h-full flex items-center justify-center p-4">
            <div className="max-w-md w-full bg-white p-6 rounded-lg shadow-lg border-l-4 border-red-500">
                <h3 className="text-lg font-bold text-red-600 mb-2">Error</h3>
                <p className="text-slate-600 mb-4">{errorMsg}</p>
                <button 
                onClick={handleRestart}
                className="px-4 py-2 bg-slate-800 text-white rounded hover:bg-slate-700 w-full font-bold"
                >
                Try Again
                </button>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useEffect, useRef } from 'react';

declare global {
  interface Window {
    MathJax: any;
  }
}

interface MathRendererProps {
  text: string;
  className?: string;
  inline?: boolean;
}

const MathRenderer: React.FC<MathRendererProps> = ({ text, className = "", inline = false }) => {
  const ref = useRef<HTMLDivElement>(null);

  // Pre-process text to handle newlines and ensure spaces around math delimiters for readability
  const processText = (input: string) => {
    if (!input) return "";
    // Replace newline characters with HTML line breaks
    let processed = input.replace(/\n/g, '<br />');

    // Attempt to ensure spaces around inline math delimiters ($) if missing
    // This is a heuristic: space before $ if preceded by non-space, space after $ if followed by non-space
    // Note: This is a simple regex and might not catch edge cases, but helps with "word$math$" issues.
    // We strictly avoid touching $$ display math.
    // This regex looks for a non-whitespace char, then $, then not a $.
    processed = processed.replace(/([^\s])(\$)(?!\$)/g, '$1 $2');
    // Look for $, then not $, then non-whitespace
    processed = processed.replace(/(?<!\$)(\$)([^\s])/g, '$1 $2');

    return processed;
  };

  useEffect(() => {
    let isMounted = true;

    const renderMath = async () => {
      if (window.MathJax && ref.current) {
        // Set content with processed line breaks
        ref.current.innerHTML = processText(text);

        try {
            await window.MathJax.typesetPromise([ref.current]);
        } catch (err) {
            console.debug('MathJax typesetting warning:', err);
            if (isMounted && window.MathJax.typesetClear) {
                try {
                    window.MathJax.typesetClear([ref.current]);
                    await window.MathJax.typesetPromise([ref.current]);
                } catch (e) { /* ignore retry failure */ }
            }
        }
      }
    };

    renderMath();

    return () => { isMounted = false; };
  }, [text]);

  const Tag = inline ? 'span' : 'div';

  return (
    <Tag 
      ref={ref} 
      className={`math-content ${className} text-inherit leading-loose`} 
      style={{ wordBreak: 'break-word' }}
    />
  );
};

export default MathRenderer;

import React from 'react';
import { QuizResult, Question, UserResponse, MarkingScheme } from '../types';
import { Icons } from '../constants';
import MathRenderer from './MathRenderer';

interface ResultsViewProps {
  result: QuizResult;
  questions: Question[];
  userResponses: UserResponse[];
  markingScheme: MarkingScheme;
  onRestart: () => void;
}

const ResultsView: React.FC<ResultsViewProps> = ({ result, questions, userResponses, markingScheme, onRestart }) => {
  const percentage = Math.round((result.totalScore / result.maxScore) * 100);

  // Determine Grade Color
  let gradeColor = "text-red-600";
  let gradeBg = "bg-red-50 border-red-200";
  if (percentage >= 80) {
    gradeColor = "text-green-600";
    gradeBg = "bg-green-50 border-green-200";
  } else if (percentage >= 50) {
    gradeColor = "text-amber-600";
    gradeBg = "bg-amber-50 border-amber-200";
  }

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-fade-in-up pb-12">
      {/* Summary Card */}
      <div className={`p-8 rounded-2xl border-2 ${gradeBg} flex flex-col md:flex-row items-center justify-between shadow-sm`}>
        <div className="mb-6 md:mb-0 text-center md:text-left">
          <h2 className={`text-3xl font-bold ${gradeColor} mb-2`}>Quiz Complete!</h2>
          <p className="text-slate-700 text-lg"><MathRenderer text={result.summary} /></p>
        </div>
        <div className="flex flex-col items-center justify-center bg-white p-6 rounded-2xl shadow-sm border border-slate-100 min-w-[200px]">
          <span className="text-sm text-slate-500 uppercase tracking-wider font-semibold mb-1">Total Score</span>
          <span className={`text-5xl font-black ${gradeColor}`}>
            {result.totalScore}<span className="text-2xl text-slate-400">/{result.maxScore}</span>
          </span>
          <span className="text-sm font-medium text-slate-500 mt-2">{percentage}% Accuracy</span>
        </div>
      </div>

      {/* Questions Breakdown */}
      <div className="space-y-6">
        <h3 className="text-xl font-bold text-slate-800 px-2">Detailed Breakdown</h3>
        {result.evaluations.map((evaluation, idx) => {
          const question = questions.find(q => q.id === evaluation.questionId);
          const userResp = userResponses.find(r => r.questionId === evaluation.questionId);
          const option = question?.options.find(o => o.id === userResp?.selectedOptionId);
          const correctOption = question?.options.find(o => o.id === evaluation.correctOptionId);

          if (!question) return null;

          return (
            <div key={idx} className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
              {/* Question Header */}
              <div className="bg-slate-50 px-6 py-4 border-b border-slate-100 flex justify-between items-start">
                <div className="flex-1 pr-4">
                    <span className="text-xs font-bold text-slate-500 uppercase tracking-wide">Question {idx + 1}</span>
                    <div className="text-lg font-medium text-slate-900 mt-1">
                        <MathRenderer text={question.text} />
                    </div>
                </div>
                <div className="flex items-center space-x-4 flex-none">
                     <div className="flex flex-col items-end">
                        <span className="text-xs text-slate-400 font-medium uppercase">Answer</span>
                        <span className={`font-bold ${evaluation.answerScore > 0 ? 'text-green-600' : 'text-red-500'}`}>
                            {evaluation.answerScore}/{markingScheme.answerPoints}
                        </span>
                     </div>
                     <div className="flex flex-col items-end">
                        <span className="text-xs text-slate-400 font-medium uppercase">Logic</span>
                        <span className={`font-bold ${evaluation.reasonScore >= (markingScheme.reasonPoints * 0.8) ? 'text-green-600' : evaluation.reasonScore >= (markingScheme.reasonPoints * 0.4) ? 'text-amber-500' : 'text-red-500'}`}>
                            {evaluation.reasonScore}/{markingScheme.reasonPoints}
                        </span>
                     </div>
                </div>
              </div>

              <div className="p-6 grid grid-cols-1 md:grid-cols-2 gap-8">
                {/* User Side */}
                <div className="space-y-4">
                  <div>
                    <span className="text-xs font-semibold text-slate-400 uppercase">Your Answer</span>
                    <div className={`mt-1 p-3 rounded-lg border flex items-center ${
                      evaluation.isAnswerCorrect 
                        ? 'bg-green-50 border-green-200 text-green-900' 
                        : 'bg-red-50 border-red-200 text-red-900'
                    }`}>
                       {evaluation.isAnswerCorrect ? <Icons.CheckCircle className="w-5 h-5 mr-2 flex-none" /> : <Icons.XCircle className="w-5 h-5 mr-2 flex-none" />}
                       <span className="font-medium">
                         {option ? <MathRenderer text={option.text} inline /> : "No selection"}
                       </span>
                    </div>
                  </div>

                  <div>
                    <span className="text-xs font-semibold text-slate-400 uppercase">Your Reasoning</span>
                    <div className="mt-1 p-3 rounded-lg border border-slate-200 bg-slate-50 text-slate-700 text-sm min-h-[60px]">
                      {userResp?.reasoning ? <MathRenderer text={userResp.reasoning} /> : <span className="text-slate-400 italic">No reasoning provided.</span>}
                    </div>
                  </div>
                </div>

                {/* AI Feedback Side */}
                <div className="space-y-4 relative">
                    <div className="absolute left-0 top-0 bottom-0 w-px bg-slate-100 -ml-4 hidden md:block"></div>

                  {!evaluation.isAnswerCorrect && (
                     <div>
                        <span className="text-xs font-semibold text-slate-400 uppercase">Correct Answer</span>
                        <div className="mt-1 p-3 rounded-lg border border-indigo-100 bg-indigo-50 text-indigo-900 flex items-center">
                            <Icons.CheckCircle className="w-5 h-5 mr-2 text-indigo-600 flex-none" />
                            <span className="font-medium">
                                <MathRenderer text={correctOption?.text || ""} inline />
                            </span>
                        </div>
                    </div>
                  )}

                  <div>
                     <span className="text-xs font-semibold text-slate-400 uppercase">Feedback on Reasoning</span>
                     <div className="mt-1 text-sm text-slate-700 leading-relaxed">
                        <div className="mb-3 bg-white p-3 rounded border border-slate-100 shadow-sm">
                            <span className="font-semibold text-indigo-600 block mb-1">AI Evaluation</span> 
                            <MathRenderer text={evaluation.reasonFeedback} />
                        </div>
                        <div className="p-3 bg-yellow-50 border border-yellow-100 rounded-lg text-yellow-900 text-xs">
                            <span className="font-bold block mb-1 text-yellow-800">Optimal Reasoning Path</span>
                            <MathRenderer text={evaluation.correctReasoning} />
                        </div>
                     </div>
                  </div>
                </div>
              </div>
            </div>
          );
        })}
      </div>

      <div className="flex justify-center pt-8 pb-12">
        <button 
            onClick={onRestart}
            className="flex items-center px-8 py-3 bg-indigo-600 text-white rounded-full font-bold shadow-lg hover:bg-indigo-700 hover:shadow-indigo-300 transition-all transform hover:-translate-y-1"
        >
            <Icons.RefreshCw className="w-5 h-5 mr-2" />
            Take Another Quiz
        </button>
      </div>
    </div>
  );
};

