import { GoogleGenAI, Type, Schema } from "@google/genai";
import { Question, UserResponse, QuizResult, MarkingScheme } from "../types";

// NOTE: In a real app, API_KEY should be handled securely. 
// For this frontend-only demo, we expect it in process.env.
const apiKey = process.env.API_KEY || '';

const ai = new GoogleGenAI({ apiKey });

const QUIZ_SCHEMA: Schema = {
  type: Type.ARRAY,
  items: {
    type: Type.OBJECT,
    properties: {
      id: { type: Type.STRING },
      text: { type: Type.STRING },
      options: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            id: { type: Type.STRING },
            text: { type: Type.STRING }
          },
          required: ["id", "text"]
        }
      },
      correctOptionId: { type: Type.STRING },
      correctReasoning: { type: Type.STRING }
    },
    required: ["id", "text", "options", "correctOptionId", "correctReasoning"]
  }
};

const EVALUATION_SCHEMA: Schema = {
  type: Type.OBJECT,
  properties: {
    evaluations: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          questionId: { type: Type.STRING },
          answerScore: { type: Type.NUMBER, description: "Points awarded for correct option" },
          reasonScore: { type: Type.NUMBER, description: "Points awarded for reasoning" },
          totalScore: { type: Type.NUMBER },
          isAnswerCorrect: { type: Type.BOOLEAN },
          reasonFeedback: { type: Type.STRING },
          correctReasoning: { type: Type.STRING },
          correctOptionId: { type: Type.STRING }
        },
        required: ["questionId", "answerScore", "reasonScore", "totalScore", "isAnswerCorrect", "reasonFeedback", "correctReasoning", "correctOptionId"]
      }
    },
    totalScore: { type: Type.NUMBER },
    maxScore: { type: Type.NUMBER },
    summary: { type: Type.STRING }
  },
  required: ["evaluations", "totalScore", "maxScore", "summary"]
};

export const generateQuiz = async (topic: string, difficulty: string, count: number = 5): Promise<Question[]> => {
  const model = "gemini-2.5-flash";

  const prompt = `
    Generate ${count} multiple-choice questions on the topic(s) of: "${topic}".
    Difficulty: "${difficulty}".

    If multiple topics are listed, ensure the questions are a Mix of these topics.

    FORMATTING RULES FOR MATH & LOGIC:
    1. **MATH SPACING**: Always insert a space between text and math delimiters.
       - BAD: "find$x$."
       - GOOD: "find $ x $ ."

    2. **LINE BREAKS & STRUCTURE**:
       - Use "\\n" explicitly to separate distinct thoughts or steps.
       - In 'correctReasoning', you MUST use bullet points for steps. Format it like this:
         "To solve this: \\n - Step 1: $ x^2 = 4 $ \\n - Step 2: Therefore $ x = 2 $"
       - NEVER put two distinct equations on the same line without a clear text separator or newline.

    3. **LATEX SYNTAX**:
       - Use ONLY '$' for inline math and '$$' for display math.
       - Double-escape backslashes (e.g. "\\\\frac").

    4. **JSON**: Output strictly valid JSON.
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: QUIZ_SCHEMA,
        systemInstruction: "You are a precise Math Engine. You care deeply about readability. You always use newlines to separate steps in reasoning."
      }
    });

    const text = response.text;
    if (!text) throw new Error("No content generated");

    return JSON.parse(text) as Question[];
  } catch (error) {
    console.error("Quiz Generation Error:", error);
    throw error;
  }
};

export const evaluateQuiz = async (
  questions: Question[], 
  userResponses: UserResponse[],
  markingScheme: MarkingScheme
): Promise<QuizResult> => {
  const model = "gemini-2.5-flash";

  // Prepare a prompt that includes both the original questions (with truth) and user answers
  const dataForAI = questions.map(q => {
    const userResp = userResponses.find(ur => ur.questionId === q.id);
    return {
      questionId: q.id,
      questionText: q.text,
      options: q.options,
      correctOptionId: q.correctOptionId,
      goldenReasoning: q.correctReasoning,
      userSelectedOptionId: userResp?.selectedOptionId || "NO_ANSWER",
      userReasoning: userResp?.reasoning || "NO_REASONING"
    };
  });

  const prompt = `
    Evaluate the following student responses.

    Scoring Rules:
    1. Answer Score: Max ${markingScheme.answerPoints} points.
    2. Reason Score: Max ${markingScheme.reasonPoints} points.

    Formatting Rules:
    - Use '$' for inline math and '$$' for display math.
    - Double-escape all backslashes (e.g., "\\\\frac").
    - Ensure spaces around '$' (e.g., " $ x $ ").
    - Use bullet points (\\n -) in feedback to separate steps.

    Data to evaluate:
    ${JSON.stringify(dataForAI, null, 2)}
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: EVALUATION_SCHEMA,
        systemInstruction: "You are a fair grader. Output strictly valid JSON."
      }
    });

    const text = response.text;
    if (!text) throw new Error("No evaluation generated");

    return JSON.parse(text) as QuizResult;
  } catch (error) {
    console.error("Evaluation Error:", error);
    throw error;
  }
};

import React, { useEffect, useRef } from 'react';

declare global {
  interface Window {
    MathJax: any;
  }
}

interface MathRendererProps {
  text: string;
  className?: string;
  inline?: boolean;
}

const MathRenderer: React.FC<MathRendererProps> = ({ text, className = "", inline = false }) => {
  const ref = useRef<HTMLDivElement>(null);

  // Pre-process text to handle newlines, spacing, and unbalanced delimiters
  const processText = (input: string) => {
    if (!input) return "";

    let processed = input;

    // 1. Balance Dollar Signs
    const dollarCount = (processed.match(/(?<!\\)\$/g) || []).length;
    if (dollarCount % 2 !== 0) {
      processed += " $"; // Close the dangling tag
    }

    // 2. Replace actual newlines with HTML breaks
    processed = processed.replace(/\n/g, '<br />');

    // 3. Handle double/triple spaces as line breaks (common AI artifact for "separation")
    processed = processed.replace(/\s{3,}/g, '<br /><br />');
    processed = processed.replace(/\s{2,}/g, '<br />');

    // 4. Spacing around Delimiters: Enforce space between [letter] and $
    processed = processed.replace(/([a-zA-Z0-9])(\$)/g, '$1 $2');
    processed = processed.replace(/(\$)([a-zA-Z0-9])/g, '$1 $2');

    // 5. Replace bullet points "- " at start of lines (after breaks) with a visual bullet
    // This helps simple markdown-like lists render better
    processed = processed.replace(/(<br \/>|^)\s*-\s/g, '$1&bull; ');

    return processed;
  };

  useEffect(() => {
    let isMounted = true;

    const renderMath = async () => {
      if (window.MathJax && ref.current) {
        // Set content with processed text
        ref.current.innerHTML = processText(text);

        try {
            await window.MathJax.typesetPromise([ref.current]);
        } catch (err) {
            // console.debug('MathJax typesetting warning:', err);
            if (isMounted && window.MathJax.typesetClear) {
                try {
                    window.MathJax.typesetClear([ref.current]);
                    await window.MathJax.typesetPromise([ref.current]);
                } catch (e) { /* ignore retry failure */ }
            }
        }
      }
    };

    renderMath();

    return () => { isMounted = false; };
  }, [text]);

  const Tag = inline ? 'span' : 'div';

  return (
    <Tag 
      ref={ref} 
      className={`math-content ${className} text-inherit leading-loose tracking-wide`} 
      style={{ wordBreak: 'break-word', overflowWrap: 'anywhere' }}
    />
  );
};

export default MathRenderer;

