import { SavedResult } from './types';

const DB_KEY = 'mindgrade_db_results';

export const db = {
  /**
   * Saves a result to the database
   */
  saveResult: (result: SavedResult): void => {
    const history = db.getAllResults();
    history.unshift(result); // Newest first
    localStorage.setItem(DB_KEY, JSON.stringify(history));
  },

  /**
   * Retrieves all results from the database
   */
  getAllResults: (): SavedResult[] => {
    const data = localStorage.getItem(DB_KEY);
    if (!data) return [];
    try {
      return JSON.parse(data);
    } catch (e) {
      console.error("Database corruption detected. Clearing history.");
      localStorage.removeItem(DB_KEY);
      return [];
    }
  },

  /**
   * Deletes a specific record
   */
  deleteResult: (id: string): void => {
    const history = db.getAllResults().filter(r => r.id !== id);
    localStorage.setItem(DB_KEY, JSON.stringify(history));
  },

  /**
   * Clears all database records
   */
  clearAll: (): void => {
    localStorage.removeItem(DB_KEY);
  }
};

import { db } from './db';
import { SavedResult, QuizResult, QuizConfig } from './types';

/**
 * MindGrade Mock Backend API
 * This simulates a separate server with routes and logic.
 */
export const backendApi = {
  /**
   * POST /api/results
   * Saves a new quiz attempt
   */
  submitResult: async (result: QuizResult, config: QuizConfig): Promise<SavedResult> => {
    // Simulate network delay
    await new Promise(resolve => setTimeout(resolve, 800));

    const savedRecord: SavedResult = {
      id: `att-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
      timestamp: Date.now(),
      topic: config.topic,
      difficulty: config.difficulty,
      score: result.totalScore,
      maxScore: result.maxScore,
      accuracy: Math.round((result.totalScore / result.maxScore) * 100),
      result,
      config
    };

    db.saveResult(savedRecord);
    return savedRecord;
  },

  /**
   * GET /api/history
   * Returns list of all past attempts
   */
  getHistory: async (): Promise<SavedResult[]> => {
    await new Promise(resolve => setTimeout(resolve, 400));
    return db.getAllResults();
  },

  /**
   * DELETE /api/results/:id
   */
  deleteAttempt: async (id: string): Promise<void> => {
    await new Promise(resolve => setTimeout(resolve, 300));
    db.deleteResult(id);
  },

  /**
   * GET /api/stats
   * Returns aggregate statistics for the user
   */
  getStats: async () => {
    const history = db.getAllResults();
    if (history.length === 0) return null;

    const totalAttempts = history.length;
    const avgAccuracy = Math.round(history.reduce((acc, curr) => acc + curr.accuracy, 0) / totalAttempts);
    const bestScore = Math.max(...history.map(h => h.accuracy));

    return {
      totalAttempts,
      avgAccuracy,
      bestScore,
      lastTopic: history[0].topic
    };
  }
};

