                                className="lg:hidden p-2 rounded-lg bg-slate-100 text-slate-600"
                            >
                                <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="3" y1="12" x2="21" y2="12"></line><line x1="3" y1="6" x2="21" y2="6"></line><line x1="3" y1="18" x2="21" y2="18"></line></svg>
                            </button>
                        </div>
                    )}
                </div>
            </div>
        </header>
      )}

      <main className="flex-grow flex overflow-hidden relative">
        {appState === AppState.HOME && (
            <LandingPage onGetStarted={() => setAppState(AppState.WELCOME)} />
        )}

        {appState === AppState.WELCOME && (
          <div className="w-full h-full overflow-y-auto p-4 md:p-8 flex items-start justify-center bg-slate-50/50 pt-8 md:pt-12">
            <QuizSetup onStartAI={handleStartAI} onStartManual={handleStartManual} />
          </div>
        )}

        {appState === AppState.HISTORY && (
          <div className="w-full h-full overflow-y-auto p-4 md:p-8 flex items-start justify-center bg-slate-50">
             <HistoryView onBack={() => setAppState(AppState.WELCOME)} onDetail={handleViewAttemptDetails} />
          </div>
        )}

        {appState === AppState.GENERATING && (
          <div className="w-full h-full flex items-center justify-center">
            <LoadingSpinner message="AI is crafting your exam paper..." />
          </div>
        )}

        {appState === AppState.QUIZ && questions.length > 0 && (
          <>
             <div className="flex-1 flex flex-col h-full overflow-hidden bg-slate-100">
                <QuizCard 
                    question={questions[currentQuestionIndex]}
                    response={userResponses[currentQuestionIndex]}
                    onOptionSelect={handleOptionSelect}
                    onReasonChange={handleReasonChange}
                    questionIndex={currentQuestionIndex}
                    totalQuestions={questions.length}
                    onNext={handleNext}
                    onPrev={handlePrev}
                    isMarked={markedIndices.has(currentQuestionIndex)}
                    onToggleMark={handleToggleMark}
                />
             </div>

             <div className={`
                fixed inset-y-0 right-0 w-80 transform transition-transform duration-300 ease-in-out z-40 lg:relative lg:transform-none lg:w-80 flex-none
                ${showMobileNav ? 'translate-x-0' : 'translate-x-full lg:translate-x-0'}
             `}>
                <QuestionNavigation 
                    totalQuestions={questions.length}
                    currentQuestionIndex={currentQuestionIndex}
                    visitedIndices={visitedIndices}
                    markedIndices={markedIndices}
                    userResponses={userResponses.reduce((acc, curr, idx) => ({ ...acc, [idx]: !!curr.selectedOptionId }), {})}
                    onNavigate={handleNavigate}
                    onSubmit={submitQuiz}
                />
             </div>

             {showMobileNav && (
                <div 
                    className="fixed inset-0 bg-black/50 z-30 lg:hidden"
                    onClick={() => setShowMobileNav(false)}
                />
             )}
          </>
        )}

        {appState === AppState.SUBMITTING && (
           <div className="w-full h-full flex items-center justify-center bg-white">
             <LoadingSpinner message="Grading & saving to records..." />
           </div>
        )}

        {appState === AppState.RESULTS && quizResult && (
          <div className="w-full h-full overflow-y-auto p-4 md:p-8 bg-slate-50">
             <ResultsView 
                result={quizResult} 
                questions={questions} 
                userResponses={userResponses} 
                markingScheme={markingScheme}
                onRestart={handleRestart}
            />
          </div>
        )}

        {appState === AppState.ERROR && (
          <div className="w-full h-full flex items-center justify-center p-4">
            <div className="max-w-md w-full bg-white p-6 rounded-lg shadow-lg border-l-4 border-red-500">
                <h3 className="text-lg font-bold text-red-600 mb-2">Error</h3>
                <p className="text-slate-600 mb-4">{errorMsg}</p>
                <button 
                onClick={handleRestart}
                className="px-4 py-2 bg-slate-800 text-white rounded hover:bg-slate-700 w-full font-bold"
                >
                Try Again
                </button>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useEffect, useState } from 'react';
import { backendApi } from '../backend';
import { SavedResult } from '../types';
import { Icons } from '../constants';
import LoadingSpinner from './LoadingSpinner';

interface HistoryViewProps {
  onBack: () => void;
  onDetail: (result: SavedResult) => void;
}

const HistoryView: React.FC<HistoryViewProps> = ({ onBack, onDetail }) => {
  const [history, setHistory] = useState<SavedResult[]>([]);
  const [loading, setLoading] = useState(true);
  const [stats, setStats] = useState<any>(null);

  useEffect(() => {
    const fetchData = async () => {
      const data = await backendApi.getHistory();
      const statsData = await backendApi.getStats();
      setHistory(data);
      setStats(statsData);
      setLoading(false);
    };
    fetchData();
  }, []);

  const handleDelete = async (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (confirm("Delete this attempt record?")) {
      await backendApi.deleteAttempt(id);
      setHistory(prev => prev.filter(h => h.id !== id));
    }
  };

  const formatDate = (timestamp: number) => {
    return new Date(timestamp).toLocaleDateString(undefined, {
      month: 'short',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  if (loading) return <div className="w-full flex justify-center py-20"><LoadingSpinner message="Fetching history..." /></div>;

  return (
    <div className="max-w-4xl w-full animate-fade-in-up pb-12">
      <div className="flex items-center justify-between mb-8">
        <div>
          <h2 className="text-3xl font-extrabold text-slate-900">Attempt History</h2>
          <p className="text-slate-500">Review your past performance and growth.</p>
        </div>
        <button 
          onClick={onBack}
          className="p-2 bg-white border border-slate-200 rounded-lg text-slate-600 hover:bg-slate-50 transition-all flex items-center"
        >
          <Icons.ChevronLeft className="w-4 h-4 mr-2" />
          Back to Setup
        </button>
      </div>

      {/* Stats Cards */}
      {stats && (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-10">
          <div className="bg-indigo-600 p-6 rounded-2xl text-white shadow-lg shadow-indigo-100">
             <span className="text-xs font-bold uppercase tracking-wider opacity-80">Total Tests</span>
             <div className="text-3xl font-black mt-1">{stats.totalAttempts}</div>
          </div>
          <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
             <span className="text-xs font-bold text-slate-400 uppercase tracking-wider">Avg. Accuracy</span>
             <div className="text-3xl font-black text-slate-800 mt-1">{stats.avgAccuracy}%</div>
          </div>
          <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
             <span className="text-xs font-bold text-slate-400 uppercase tracking-wider">Best Score</span>
             <div className="text-3xl font-black text-green-600 mt-1">{stats.bestScore}%</div>
          </div>
        </div>
      )}

      {/* History List */}
      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
        {history.length === 0 ? (
          <div className="p-20 text-center">
             <div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center mx-auto mb-4">
                <Icons.FileText className="w-8 h-8 text-slate-300" />
             </div>
             <h3 className="text-lg font-bold text-slate-800">No attempts yet</h3>
             <p className="text-slate-500">Complete a quiz to see your results here.</p>
          </div>
        ) : (
          <table className="w-full text-left">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Test Detail</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Date</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Difficulty</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Score</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase"></th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {history.map((item) => (
                <tr 
                  key={item.id} 
                  onClick={() => onDetail(item)}
                  className="hover:bg-indigo-50/30 cursor-pointer transition-colors group"
                >
                  <td className="px-6 py-4">
                    <div className="font-bold text-slate-800 line-clamp-1">{item.topic}</div>
                    <div className="text-xs text-slate-400">{item.config.questionCount} Questions</div>
                  </td>
                  <td className="px-6 py-4 text-sm text-slate-500">
                    {formatDate(item.timestamp)}
                  </td>
                  <td className="px-6 py-4">
                    <span className={`text-[10px] font-bold px-2 py-1 rounded-full uppercase border ${
                      item.difficulty === 'Hard' ? 'bg-red-50 text-red-600 border-red-100' :
                      item.difficulty === 'Medium' ? 'bg-amber-50 text-amber-600 border-amber-100' :
                      'bg-green-50 text-green-600 border-green-100'
                    }`}>
                      {item.difficulty}
                    </span>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center">
                       <div className="font-black text-slate-800 mr-2">{item.accuracy}%</div>
                       <div className="w-12 h-1.5 bg-slate-100 rounded-full overflow-hidden hidden sm:block">
                          <div className={`h-full ${item.accuracy > 70 ? 'bg-green-500' : item.accuracy > 40 ? 'bg-amber-500' : 'bg-red-500'}`} style={{ width: `${item.accuracy}%` }}></div>
                       </div>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <button 
                      onClick={(e) => handleDelete(e, item.id)}
                      className="p-2 text-slate-300 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100"
                    >
                      <Icons.Trash className="w-4 h-4" />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
};

export default HistoryView;

import { SavedResult, QuizResult, QuizConfig } from './types';

// Replace with your actual FastAPI server URL
const API_BASE_URL = 'http://localhost:8000';

/**
 * MindGrade Real Backend API Client
 * Communicates with the FastAPI server.
 */
export const backendApi = {
  /**
   * POST /api/results
   */
  submitResult: async (result: QuizResult, config: QuizConfig): Promise<SavedResult> => {
    const response = await fetch(`${API_BASE_URL}/api/results`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ result, config }),
    });

    if (!response.ok) {
      throw new Error(`Server error: ${response.statusText}`);
    }

    return await response.json();
  },

  /**
   * GET /api/history
   */
  getHistory: async (): Promise<SavedResult[]> => {
    const response = await fetch(`${API_BASE_URL}/api/history`);

    if (!response.ok) {
      throw new Error(`Server error: ${response.statusText}`);
    }

    return await response.json();
  },

  /**
   * DELETE /api/results/:id
   */
  deleteAttempt: async (id: string): Promise<void> => {
    const response = await fetch(`${API_BASE_URL}/api/results/${id}`, {
      method: 'DELETE',
    });

    if (!response.ok) {
      throw new Error(`Server error: ${response.statusText}`);
    }
  },

  /**
   * GET /api/stats
   */
  getStats: async () => {
    const response = await fetch(`${API_BASE_URL}/api/stats`);

    if (!response.ok) {
      return null;
    }

    return await response.json();
  }
};
